async (params, browser) => {
  // Open track page
  await browser.open(`${params.track_url}`)

  // Wait for track to load
  await browser.waitForSelector('.soundTitle__title, h1, [class*=\'listenDetails\']', 15000)

  // Let page render
  await browser.wait(2000)

  // Scroll to comments section
  await browser.scroll({ direction: 'down', amount: 2000 })

  await browser.wait(2000)

  // Scroll to load more comments
  await browser.scroll({ direction: 'down', amount: 2000 })

  await browser.wait(1500)

  // Extract comments
  const comments_data = await browser.evaluate(`const comments = []; const commentEls = document.querySelectorAll('.commentItem, [class*="commentItem"], [class*="comment-item"]'); for (let i = 0; i < Math.min(commentEls.length, 20); i++) { const el = commentEls[i]; const authorEl = el.querySelector('.commentItem__username a, [class*="username"] a, [class*="author"] a'); const contentEl = el.querySelector('.commentItem__body, [class*="body"], [class*="text"]'); const dateEl = el.querySelector('time, [class*="timestamp"], [class*="time"]'); const positionEl = el.querySelector('[class*="atTime"], [class*="position"]'); if (contentEl && contentEl.textContent.trim().length > 0) { comments.push({ author: authorEl ? authorEl.textContent.trim() : 'Anonymous', content: contentEl ? contentEl.textContent.trim().substring(0, 300) : '', date: dateEl ? (dateEl.getAttribute('datetime') || dateEl.textContent.trim()) : '', timestamp_position: positionEl ? positionEl.textContent.trim() : '' }); } } const totalEl = document.querySelector('[class*="commentCount"], [class*="comment"] span'); return { total_comments: totalEl ? totalEl.textContent.trim() : '', scraped_count: comments.length, comments: comments, url: window.location.href }`)

  return comments_data
}
